const data = items[0].json;

// 🔹 Dados básicos
const resultados = data.resultados || [];
const completarCadastroUrl = data.completar_cadastro_url || "";
const numero = data.telefone || data.numero;

// 🔹 Normalizador
const getItem = (r) => r.item || r;

// 🔹 Separar
const nacionais = resultados.filter(r => getItem(r).escopo === "nacional");
const locais = resultados.filter(r => getItem(r).escopo === "local");

// 🔹 Ordenar
const ordenarPorNota = (arr) =>
  [...arr].sort((a, b) => (getItem(b).nota ?? 0) - (getItem(a).nota ?? 0));

// 🔹 Quantidades aleatórias
const qtdNacionais = Math.floor(Math.random() * 2) + 1;
const qtdLocais = Math.floor(Math.random() * 3) + 1;

// 🔹 Seleção
const topNacionais = ordenarPorNota(nacionais).slice(0, qtdNacionais);
const topLocais = ordenarPorNota(locais).slice(0, qtdLocais);

// 🔹 Junta tudo
let fornecedores = [...topNacionais, ...topLocais];

// 🔹 Embaralhar
fornecedores = fornecedores.sort(() => Math.random() - 0.5);

// 🔹 Formatter
const formatarLista = (lista) => {
  return lista
    .map((r) => {
      const item = getItem(r);

      const nome = item.razao_social || "Fornecedor";
      const site = item.site || "";

      return `- ${nome}\n${site}`;
    })
    .join("\n\n");
};

const listaFormatada = formatarLista(fornecedores);

// 🔹 Templates
const templates = [

`Achei alguns aqui que talvez ajudem:

${listaFormatada}

Tem mais resultados nessa busca:
${completarCadastroUrl}

Tomara que ajude 👍`,

`Dei uma olhada rápida aqui e apareceram esses:

${listaFormatada}

Tem mais opções nesse link:
${completarCadastroUrl}`,

`Já usei essa busca pra encontrar fornecedor uma vez e achei esses agora:

${listaFormatada}

O restante apareceu aqui:
${completarCadastroUrl}`,

`Achei esses aqui:

${listaFormatada}

Nessa busca apareceram mais alguns também:
${completarCadastroUrl}

Às vezes os menores respondem mais rápido.`
];

// 🔹 Escolha aleatória
const mensagem =
  templates[Math.floor(Math.random() * templates.length)];

// 🔹 Retorno
return [
  {
    json: {
      number: numero,
      text: mensagem
    }
  }
];

const data = items[0].json;

// 🔹 Dados básicos
const contexto = data.contexto || "";
const resultados = data.resultados || [];
const numero = data.telefone || data.numero;
const url = data.url || "https://buscafornecedor.com.br";

// 🔹 Normalizador
const getItem = (r) => r.item || r;

// 🔹 Separar por escopo
const nacionais = resultados.filter(
  r => getItem(r).escopo === "nacional"
);

const locais = resultados.filter(
  r => getItem(r).escopo === "local"
);

// 🔹 Ordenar por nota
const ordenarPorNota = (arr) =>
  [...arr].sort(
    (a, b) =>
      (getItem(b).nota ?? 0) -
      (getItem(a).nota ?? 0)
  );

// 🔹 Seleção fixa
const topNacionais =
  ordenarPorNota(nacionais).slice(0, 2);

const topLocais =
  ordenarPorNota(locais).slice(0, 4);

// 🔹 Formatter
const formatarLista = (lista) => {
  return lista
    .map((r) => {
      const item = getItem(r);

      const nome =
        item.razao_social || "Fornecedor";

      const modelo = item.modelo_negocio
        ? ` (${item.modelo_negocio})`
        : "";

      const site = item.site || "";

      return `- ${nome}${modelo}\n${site}`;
    })
    .join("\n\n");
};

// 🔹 Blocos
let blocoNacionais = "";

if (topNacionais.length > 0) {
  blocoNacionais =
    `Nacionais:\n${formatarLista(topNacionais)}`;
}

let blocoLocais = "";

if (topLocais.length > 0) {
  blocoLocais =
    `Locais:\n${formatarLista(topLocais)}`;
}

// 🔹 Contexto
const contextoTexto = contexto
  ? `"${contexto}"`
  : "o que você procura";

// 🔹 Total restante
const totalExibidos =
  topNacionais.length + topLocais.length;

const totalRestante =
  Math.max(0, resultados.length - totalExibidos);

// 🔹 Templates
const templates = [

`Separei alguns fornecedores pra ${contextoTexto}:

${blocoNacionais}

${blocoLocais}

${
  totalRestante > 0
    ? `Ainda apareceram mais ${totalRestante} resultados nessa busca:\n${url}`
    : `Busca completa:\n${url}`
}`,

`Esses foram os fornecedores mais relevantes que apareceram pra ${contextoTexto}:

${blocoNacionais}

${blocoLocais}

${
  totalRestante > 0
    ? `Tem mais opções disponíveis aqui:\n${url}`
    : `Você pode acessar tudo aqui:\n${url}`
}`,

`Dei uma filtrada aqui e esses pareceram os melhores resultados:

${blocoNacionais}

${blocoLocais}

${
  totalRestante > 0
    ? `O restante apareceu nessa busca:\n${url}`
    : `A busca completa está aqui:\n${url}`
}`,

`Achei esses fornecedores que parecem encaixar bem no que você procura:

${blocoNacionais}

${blocoLocais}

${
  totalRestante > 0
    ? `Tem mais alguns resultados filtrados aqui:\n${url}`
    : `Você consegue acessar a busca completa aqui:\n${url}`
}`
];

// 🔹 Escolha aleatória
const mensagem =
  templates[
    Math.floor(Math.random() * templates.length)
  ];

// 🔹 Retorno
return [
  {
    json: {
      number: numero,
      text: mensagem
    }
  }
];

